def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {This algorithm assigns each unvisited node a score based on its distance from the current node and the average distance 
    to all other unvisited nodes, selecting the node with the lowest score to balance localized exploration with global path efficiency.}
    """
    if len(unvisited_nodes) == 0:
        return depot_node

    average_unvisited_distances = {}
    for node in unvisited_nodes:
        distances = []
        for other_node in unvisited_nodes:
            if other_node != node:
                distances.append(distance_matrix[node][other_node])
        average_distance = np.mean(distances) if distances else 0
        average_unvisited_distances[node] = average_distance

    scores = []
    for node in unvisited_nodes:
        distance_score = distance_matrix[current_node][node]
        global_score = average_unvisited_distances[node]
        total_score = distance_score + global_score
        scores.append((total_score, node))

    scores.sort()
    _, next_node = scores[0]
    return next_node

